import React, { useEffect, useMemo, useRef, useState } from 'react';
import ProductForm from './ProductForm';
import Modal from './Modal';
import DeleteConfirmModal from './common/DeleteConfirmModal';
import useResizableColumns from './useResizableColumns';
import { getProductTypes, getProducts, createProduct, updateProduct, deleteProduct } from '../services/api';
const filterOptions = ['Active Products', 'Inactive Products'];
const columnFilterOptions = [
    'Contains',
    'Does not contain',
    'Equals',
    'Does not equal',
    'Begins with',
    'Ends with',
    'Blank',
    'Not blank',
];
const allColumns = [
    { field: 'name', label: 'Name' },
    { field: 'productType', label: 'Product Type' },
    { field: 'manufacturer', label: 'Manufacturer' },
    { field: 'partNo', label: 'Part No' },
    { field: 'cost', label: 'Cost' },
    { field: 'active', label: 'Active' },
    { field: 'description', label: 'Description' },
];
const defaultColumnWidths = {
    name: 220,
    productType: 220,
    manufacturer: 220,
    partNo: 180,
    cost: 150,
    active: 140,
    description: 320,
};
const defaultColumnFilter = {
    operator: 'Contains',
    value: '',
};
const getProductColumnValue = (item, field) => {
    if (field === 'productType')
        return item.product_type ?? '';
    if (field === 'active')
        return item.active ? 'Yes' : 'No';
    return item[field] ?? '';
};
const doesValueMatchColumnFilter = (rawValue, filter) => {
    const value = String(rawValue ?? '').trim().toLowerCase();
    const filterValue = filter.value.trim().toLowerCase();
    if (filter.operator === 'Blank')
        return value.length === 0;
    if (filter.operator === 'Not blank')
        return value.length > 0;
    if (!filterValue)
        return true;
    switch (filter.operator) {
        case 'Contains':
            return value.includes(filterValue);
        case 'Does not contain':
            return !value.includes(filterValue);
        case 'Equals':
            return value === filterValue;
        case 'Does not equal':
            return value !== filterValue;
        case 'Begins with':
            return value.startsWith(filterValue);
        case 'Ends with':
            return value.endsWith(filterValue);
        default:
            return true;
    }
};
const ProductTable = () => {
    const [products, setProducts] = useState([]);
    const [open, setOpen] = useState(false);
    const [editing, setEditing] = useState(null);
    const [activeFilter, setActiveFilter] = useState(filterOptions[0]);
    const [actionAnchorEl, setActionAnchorEl] = useState(null);
    const [actionRow, setActionRow] = useState(null);
    const [columnsAnchorEl, setColumnsAnchorEl] = useState(null);
    const [visibleColumns, setVisibleColumns] = useState(allColumns.map((column) => column.field));
    const [filterMenuField, setFilterMenuField] = useState(null);
    const [columnFilters, setColumnFilters] = useState({});
    const [draftColumnFilter, setDraftColumnFilter] = useState(defaultColumnFilter);
    const [currentPage, setCurrentPage] = useState(1);
    const [pageSize, setPageSize] = useState(10);
    const [sortField, setSortField] = useState('name');
    const [sortDirection, setSortDirection] = useState('asc');
    const [productTypes, setProductTypes] = useState([]);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [deleteTarget, setDeleteTarget] = useState(null);
    const [deleteLoading, setDeleteLoading] = useState(false);
    const [deleteError, setDeleteError] = useState('');
    const actionMenuRef = useRef(null);
    const columnsMenuRef = useRef(null);
    const filterMenuRef = useRef(null);
    const { getColumnStyle, renderResizeHandle } = useResizableColumns(defaultColumnWidths);
    const fetchProducts = async () => {
        setLoading(true);
        try {
            const response = await getProducts();
            setProducts(response.data);
        }
        catch (error) {
            console.error('Error fetching products:', error);
        }
        finally {
            setLoading(false);
        }
    };
    useEffect(() => {
        fetchProducts();
        loadProductTypes();
    }, []);
    const loadProductTypes = async () => {
        try {
            const response = await getProductTypes();
            setProductTypes(response.data);
        }
        catch (error) {
            console.error('Unable to load product types:', error);
        }
    };
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (actionMenuRef.current && !actionMenuRef.current.contains(event.target) && actionAnchorEl && !actionAnchorEl.contains(event.target)) {
                setActionAnchorEl(null);
            }
            if (columnsMenuRef.current && !columnsMenuRef.current.contains(event.target)) {
                setColumnsAnchorEl(null);
            }
            if (filterMenuRef.current && !filterMenuRef.current.contains(event.target)) {
                setFilterMenuField(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [actionAnchorEl]);
    const filteredProducts = useMemo(() => {
        return products.filter((item) => {
            const matchesActiveFilter = activeFilter === filterOptions[0] ? item.active : true;
            if (!matchesActiveFilter)
                return false;
            return allColumns.every((column) => {
                const filter = columnFilters[column.field];
                if (!filter)
                    return true;
                return doesValueMatchColumnFilter(getProductColumnValue(item, column.field), filter);
            });
        });
    }, [activeFilter, columnFilters, products]);
    const sortedProducts = useMemo(() => {
        return [...filteredProducts].sort((a, b) => {
            const aValue = getProductColumnValue(a, sortField);
            const bValue = getProductColumnValue(b, sortField);
            const result = aValue.toString().localeCompare(bValue.toString(), undefined, { numeric: true, sensitivity: 'base' });
            return sortDirection === 'asc' ? result : -result;
        });
    }, [filteredProducts, sortDirection, sortField]);
    const totalPages = Math.max(1, Math.ceil(sortedProducts.length / pageSize));
    const startIndex = (currentPage - 1) * pageSize;
    const endIndex = startIndex + pageSize;
    const paginatedProducts = sortedProducts.slice(startIndex, endIndex);
    useEffect(() => {
        if (currentPage > totalPages) {
            setCurrentPage(totalPages);
        }
    }, [currentPage, totalPages]);
    const handleOpen = (item = null) => {
        if (item) {
            const typeObj = productTypes.find(pt => pt.display_name === item.product_type);
            setEditing({
                id: item.id,
                name: item.name || '',
                productType: typeObj ? typeObj.id : '',
                manufacturer: item.manufacturer || '',
                partNo: item.partNo || '',
                cost: item.cost || '',
                description: item.description || '',
                active: item.active ?? true,
            });
        }
        else {
            setEditing(null);
        }
        setOpen(true);
    };
    const handleClose = () => {
        setOpen(false);
        setEditing(null);
    };
    const handleSave = async (product) => {
        setSaving(true);
        try {
            const typeObj = productTypes.find(pt => pt.id === product.productType);
            const payload = {
                name: product.name,
                product_type: typeObj ? typeObj.display_name : '',
                manufacturer: product.manufacturer,
                part_no: product.partNo,
                cost: product.cost,
                description: product.description,
                active: product.active,
            };
            if (product.id) {
                await updateProduct(product.id, payload);
            }
            else {
                await createProduct(payload);
            }
            fetchProducts();
            handleClose();
        }
        catch (error) {
            console.error('Error saving product:', error);
        }
        finally {
            setSaving(false);
        }
    };
    const handleDelete = (id) => {
        const item = actionRow || products.find((currentItem) => currentItem.id === id) || { id };
        setDeleteTarget(item);
        setDeleteError('');
        setActionAnchorEl(null);
    };
    const handleConfirmDelete = async () => {
        if (!deleteTarget) {
            return;
        }
        setDeleteLoading(true);
        setDeleteError('');
        try {
            await deleteProduct(deleteTarget.id);
            await fetchProducts();
            setDeleteTarget(null);
        }
        catch (error) {
            console.error('Error deleting product:', error);
            setDeleteError('Unable to delete this product. Please try again.');
        }
        finally {
            setDeleteLoading(false);
        }
    };
    const handleCancelDelete = () => {
        if (deleteLoading) {
            return;
        }
        setDeleteTarget(null);
        setDeleteError('');
    };
    const handleClearFilters = () => {
        setActiveFilter(filterOptions[0]);
        setColumnFilters({});
        setFilterMenuField(null);
        setDraftColumnFilter(defaultColumnFilter);
        setVisibleColumns(allColumns.map((column) => column.field));
        setCurrentPage(1);
    };
    const handleOpenColumnFilter = (field) => {
        setDraftColumnFilter(columnFilters[field] ?? defaultColumnFilter);
        setFilterMenuField((currentField) => (currentField === field ? null : field));
    };
    const handleApplyColumnFilter = (field) => {
        const needsValue = draftColumnFilter.operator !== 'Blank' && draftColumnFilter.operator !== 'Not blank';
        if (needsValue && !draftColumnFilter.value.trim()) {
            handleResetColumnFilter(field);
            return;
        }
        setColumnFilters((prev) => ({
            ...prev,
            [field]: {
                ...draftColumnFilter,
                value: needsValue ? draftColumnFilter.value : '',
            },
        }));
        setFilterMenuField(null);
        setCurrentPage(1);
    };
    const handleResetColumnFilter = (field) => {
        setColumnFilters((prev) => {
            const next = { ...prev };
            delete next[field];
            return next;
        });
        setDraftColumnFilter(defaultColumnFilter);
        setFilterMenuField(null);
        setCurrentPage(1);
    };
    const handleSort = (field) => {
        if (sortField === field) {
            setSortDirection((currentDirection) => (currentDirection === 'asc' ? 'desc' : 'asc'));
        }
        else {
            setSortField(field);
            setSortDirection('asc');
        }
        setCurrentPage(1);
    };
    const actionMenuStyle = actionAnchorEl
        ? {
            top: actionAnchorEl.getBoundingClientRect().bottom + window.scrollY,
            left: actionAnchorEl.getBoundingClientRect().left + window.scrollX,
        }
        : {};
    const renderColumnHeader = (field, label) => {
        const hasFilter = Boolean(columnFilters[field]);
        const isValueDisabled = draftColumnFilter.operator === 'Blank' || draftColumnFilter.operator === 'Not blank';
        return (<th className="relative px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-slate-500" style={getColumnStyle(field)}>
        <div className="flex items-center justify-between gap-2">
          <button type="button" onClick={() => handleSort(field)} className="inline-flex items-center gap-1 text-left">
            {label}
            <span className={`text-[10px] leading-none ${sortField === field ? 'text-blue-600' : 'text-slate-400'}`} aria-hidden="true">
              {sortField === field && sortDirection === 'desc' ? '\u25BC' : '\u25B2'}
            </span>
          </button>
          <button type="button" onClick={(event) => {
                event.stopPropagation();
                handleOpenColumnFilter(field);
            }} className={`rounded p-1 hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500 ${hasFilter ? 'text-blue-600' : 'text-slate-500'}`} aria-label={`Filter ${label}`}>
            <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M2 3H14M4.5 7H11.5M6.5 11H9.5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/>
            </svg>
          </button>
        </div>

        {filterMenuField === field && (<div ref={filterMenuRef} className="absolute right-2 top-10 z-20 w-48 rounded-md border border-slate-300 bg-white p-3 text-slate-700 shadow-xl">
            <select value={draftColumnFilter.operator} onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, operator: event.target.value }))} className="mb-2 w-full rounded border border-slate-300 bg-white px-2 py-2 text-sm font-normal normal-case tracking-normal text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500">
              {columnFilterOptions.map((option) => (<option key={option} value={option}>
                  {option}
                </option>))}
            </select>
            <div className="relative">
              <span className="pointer-events-none absolute left-2 top-1/2 -translate-y-1/2 text-slate-400">
                <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M7 12A5 5 0 1 0 7 2a5 5 0 0 0 0 10ZM10.5 10.5L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              </span>
              <input value={draftColumnFilter.value} onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, value: event.target.value }))} disabled={isValueDisabled} placeholder="Filter..." className="w-full rounded border border-slate-300 bg-white py-2 pl-7 pr-2 text-sm font-normal normal-case tracking-normal text-slate-900 placeholder:text-slate-400 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-100"/>
            </div>
            <div className="mt-4 flex justify-end gap-2">
              <button type="button" onClick={() => handleApplyColumnFilter(field)} className="rounded border border-slate-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
                Apply
              </button>
              <button type="button" onClick={() => handleResetColumnFilter(field)} className="rounded border border-slate-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
                Reset
              </button>
            </div>
          </div>)}
        {renderResizeHandle(field)}
      </th>);
    };
    return (<div className="rounded-xl border border-slate-200 bg-white p-4 shadow-sm sm:p-6 space-y-5">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <select value={activeFilter} onChange={(e) => {
            setActiveFilter(e.target.value);
            setCurrentPage(1);
        }} className="w-full md:w-64 rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500">
            {filterOptions.map((option) => (<option key={option} value={option}>
                {option}
              </option>))}
          </select>
          <button onClick={() => handleOpen()} className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500">
            New
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button onClick={handleClearFilters} className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
            Clear All Filters
          </button>
          <div className="relative">
            <button onClick={(e) => setColumnsAnchorEl(e.currentTarget)} className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
              &#9654; Select Columns
            </button>
            {columnsAnchorEl && (<div ref={columnsMenuRef} className="absolute right-0 z-10 mt-1 w-56 rounded-md border border-slate-300 bg-white p-2 shadow-lg">
                {allColumns.map((column) => (<label key={column.field} className="flex cursor-pointer items-center gap-2 rounded-sm px-2 py-1 hover:bg-slate-100">
                    <input type="checkbox" checked={visibleColumns.includes(column.field)} onChange={() => {
                    setVisibleColumns((prev) => prev.includes(column.field)
                        ? prev.filter((value) => value !== column.field)
                        : [...prev, column.field]);
                }} className="h-4 w-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"/>
                    <span className="text-sm text-slate-700">{column.label}</span>
                  </label>))}
              </div>)}
          </div>
        </div>
      </div>

      {loading && (<div className="flex justify-center items-center py-8">
          <span className="h-10 w-10 animate-spin rounded-full border-b-2 border-t-2 border-blue-600"></span>
        </div>)}
      <div className="overflow-x-auto">
        <table className="min-w-full table-fixed divide-y divide-gray-200">
          <thead className="bg-slate-50">
            <tr>
              <th className="w-14 px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-slate-500"></th>
              {visibleColumns.includes('name') && renderColumnHeader('name', 'Name')}
              {visibleColumns.includes('productType') && renderColumnHeader('productType', 'Product Type')}
              {visibleColumns.includes('manufacturer') && renderColumnHeader('manufacturer', 'Manufacturer')}
              {visibleColumns.includes('partNo') && renderColumnHeader('partNo', 'Part No')}
              {visibleColumns.includes('cost') && renderColumnHeader('cost', 'Cost')}
              {visibleColumns.includes('active') && renderColumnHeader('active', 'Active')}
              {visibleColumns.includes('description') && renderColumnHeader('description', 'Description')}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200 bg-white">
            {paginatedProducts.map((item) => (<tr key={item.id} className="transition-colors duration-150 hover:bg-slate-50">
                <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900">
                  <button onClick={(event) => {
                event.stopPropagation();
                setActionRow(item);
                setActionAnchorEl(event.currentTarget);
            }} className="text-slate-400 hover:text-slate-600" aria-label="Actions">
                    <span style={{ display: 'inline-block', lineHeight: 0 }}>
                      <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <rect y="4" width="20" height="2" rx="1" fill="currentColor"/>
                        <rect y="9" width="20" height="2" rx="1" fill="currentColor"/>
                        <rect y="14" width="20" height="2" rx="1" fill="currentColor"/>
                      </svg>
                    </span>
                  </button>
                </td>
                {visibleColumns.includes('name') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('name')}>{item.name}</td>}
                {visibleColumns.includes('productType') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('productType')}>{item.product_type}</td>}
                {visibleColumns.includes('manufacturer') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('manufacturer')}>{item.manufacturer}</td>}
                {visibleColumns.includes('partNo') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('partNo')}>{item.partNo}</td>}
                {visibleColumns.includes('cost') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('cost')}>{item.cost}</td>}
                {visibleColumns.includes('active') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('active')}>{item.active ? 'Yes' : 'No'}</td>}
                {visibleColumns.includes('description') && <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900" style={getColumnStyle('description')}>{item.description}</td>}
              </tr>))}
            {paginatedProducts.length === 0 && (<tr>
                <td colSpan={visibleColumns.length + 1} className="px-6 py-8 text-center text-sm text-slate-500">
                  No products found
                </td>
              </tr>)}
          </tbody>
        </table>
      </div>

      <div className="mt-6 flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2 text-sm text-slate-700">
          <span>Page Size:</span>
          <select value={pageSize} onChange={(e) => {
            setPageSize(Number(e.target.value));
            setCurrentPage(1);
        }} className="rounded-md border border-slate-300 bg-white px-3 py-1 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500">
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex flex-wrap items-center gap-3 text-sm text-slate-600">
          <span>
            {sortedProducts.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, sortedProducts.length)} of ${sortedProducts.length}`}
          </span>
          <div className="flex items-center gap-2">
            <button onClick={() => setCurrentPage((page) => Math.max(1, page - 1))} disabled={currentPage === 1} className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50" type="button">
              &#8592;
            </button>
            <span className="text-sm text-slate-600">Page {currentPage} of {totalPages}</span>
            <button onClick={() => setCurrentPage((page) => Math.min(totalPages, page + 1))} disabled={currentPage === totalPages} className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50" type="button">
              &#8594;
            </button>
          </div>
        </div>
      </div>

      {actionAnchorEl && (<div ref={actionMenuRef} className="fixed z-10 w-40 rounded-md border border-slate-200 bg-white shadow-lg" style={actionMenuStyle}>
          <button onClick={() => {
                if (actionRow)
                    handleOpen(actionRow);
                setActionAnchorEl(null);
            }} className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100">
            Edit
          </button>
          <button onClick={() => {
                if (actionRow)
                    handleDelete(actionRow.id);
            }} className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100">
            Delete
          </button>
        </div>)}

      <Modal
        open={open}
        title={editing ? 'Edit Asset Product' : 'Add Asset Product'}
        description={editing ? 'Update product details.' : 'Create a new asset product.'}
        onClose={handleClose}
        maxWidth="max-w-4xl"
      >
        <ProductForm editing={editing} onSave={handleSave} onClose={handleClose} productTypes={productTypes} saving={saving}/>
      </Modal>
      <DeleteConfirmModal
        isOpen={Boolean(deleteTarget)}
        title="Delete Product"
        message={deleteError || 'Are you sure you want to delete this product?'}
        itemName={deleteTarget?.name || deleteTarget?.product || deleteTarget?.id}
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
        isLoading={deleteLoading}
      />
    </div>);
};
export default ProductTable;
